import{Logger}from '../shared/logger.js';export class Stepper{constructor(selector,options={}){this.container=typeof selector==='string' ? document.querySelector(selector): selector;if(!this.container){Logger.error('Stepper container not found',{selector});return;}this.options={initialStep: 0,showProgress: true,keyboardNav: true,validation: true,onStepChange: null,onValidate: null,onComplete: null,...options};this.currentStep=this.options.initialStep;this.steps=[];this.completed=false;this.init();}init(){this.steps=Array.from(this.container.querySelectorAll('.step'));if(this.steps.length===0){Logger.warn('No steps found in stepper');return;}this.render();this.bindEvents();this.goToStep(this.currentStep);Logger.debug('Stepper initialized',{steps: this.steps.length});}render(){this.container.innerHTML=` ${this.options.showProgress ? this.renderProgress(): ''}<div class="stepper-content">${this.steps.map((step,index)=>this.renderStepContent(step,index)).join('')}</div><div class="stepper-navigation"><button type="button" class="stepper-btn stepper-prev" ${this.currentStep===0 ? 'disabled' : ''}>← Trước</button><button type="button" class="stepper-btn stepper-next">${this.currentStep===this.steps.length-1 ? 'Hoàn tất' : 'Tiếp'}→</button></div>`;}renderProgress(){const progress=((this.currentStep+1)/this.steps.length)*100;return `<div class="stepper-progress"><div class="stepper-progress-bar" style="width: ${progress}%"></div><div class="stepper-steps-indicator">${this.steps.map((_,index)=>`<div class="step-indicator ${index===this.currentStep ? 'active' : ''}${index<this.currentStep ? 'completed' : ''}" data-step="${index}"><span class="step-number">${index+1}</span></div>`).join('')}</div><div class="stepper-progress-text">Bước ${this.currentStep+1}/${this.steps.length}</div></div>`;}renderStepContent(step,index){const stepContent=step.innerHTML||step.textContent;return `<div class="stepper-step-content" data-step="${index}" style="display: ${index===this.currentStep ? 'block' : 'none'}">${stepContent}</div>`;}bindEvents(){const prevBtn=this.container.querySelector('.stepper-prev');const nextBtn=this.container.querySelector('.stepper-next');prevBtn?.addEventListener('click',()=>this.prev());nextBtn?.addEventListener('click',()=>this.next());this.container.querySelectorAll('.step-indicator').forEach(indicator=>{indicator.addEventListener('click',(e)=>{const step=parseInt(e.currentTarget.dataset.step);this.goToStep(step);});});if(this.options.keyboardNav){document.addEventListener('keydown',(e)=>{if(document.activeElement.closest('.stepper')){if(e.key==='ArrowLeft')this.prev();if(e.key==='ArrowRight')this.next();}});}}goToStep(stepIndex){if(stepIndex<0||stepIndex>=this.steps.length)return;if(this.completed)return;if(stepIndex>this.currentStep&&this.options.validation){const isValid=this.validateStep(this.currentStep);if(!isValid){Logger.warn('Step validation failed',{step: this.currentStep});return;}}this.currentStep=stepIndex;this.updateUI();if(this.options.onStepChange){this.options.onStepChange(this.currentStep);}}next(){if(this.currentStep>=this.steps.length-1){this.complete();return;}this.goToStep(this.currentStep+1);}prev(){this.goToStep(this.currentStep-1);}validateStep(stepIndex){if(!this.options.validation)return true;const stepContent=this.container.querySelector(`[data-step="${stepIndex}"]`);if(!stepContent)return true;if(this.options.onValidate){return this.options.onValidate(stepIndex,stepContent);}const requiredFields=stepContent.querySelectorAll('[required]');for(const field of requiredFields){if(!field.value.trim()){field.classList.add('error');Logger.warn('Required field empty',{field: field.name});return false;}}return true;}complete(){if(this.options.validation&&!this.validateStep(this.currentStep)){return;}this.completed=true;this.updateUI();if(this.options.onComplete){this.options.onComplete();}Logger.info('Stepper completed successfully');}updateUI(){const progressBar=this.container.querySelector('.stepper-progress-bar');if(progressBar){const progress=((this.currentStep+1)/this.steps.length)*100;progressBar.style.width=`${progress}%`;}this.container.querySelectorAll('.step-indicator').forEach((indicator,index)=>{indicator.classList.toggle('active',index===this.currentStep);indicator.classList.toggle('completed',index<this.currentStep);});this.container.querySelectorAll('.stepper-step-content').forEach((content,index)=>{content.style.display=index===this.currentStep ? 'block' : 'none';});const prevBtn=this.container.querySelector('.stepper-prev');const nextBtn=this.container.querySelector('.stepper-next');if(prevBtn){prevBtn.disabled=this.currentStep===0;}if(nextBtn){nextBtn.textContent=this.currentStep===this.steps.length-1 ? 'Hoàn tất ✓' : 'Tiếp →';nextBtn.disabled=this.completed;}const progressText=this.container.querySelector('.stepper-progress-text');if(progressText){progressText.textContent=`Bước ${this.currentStep+1}/${this.steps.length}`;}}getCurrentStep(){return this.currentStep;}getTotalSteps(){return this.steps.length;}reset(){this.currentStep=this.options.initialStep;this.completed=false;this.updateUI();}destroy(){this.container.innerHTML='';Logger.debug('Stepper destroyed');}}export function initSteppers(){document.querySelectorAll('[data-stepper]').forEach(container=>{const options=JSON.parse(container.dataset.stepper||'{}');new Stepper(container,options);});}if(typeof document!=='undefined'){if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initSteppers);}else{initSteppers();}}export default Stepper;